import React from "react";
import { useSelector } from "react-redux";

function InteractionForm() {
  const form = useSelector((state) => state.form);

  const sentimentEmoji = {
    positive: "😊",
    neutral: "😐",
    negative: "😞",
  };

  return (
    <div className="form-container">
      <h2>Log HCP Interaction</h2>

      <div className="form-field"><strong>HCP Name:</strong> {form.hcp_name || "Unknown"}</div>
      <div className="form-field"><strong>Interaction Type:</strong> {form.interaction_type || "Meeting"}</div>
      <div className="form-field"><strong>Date:</strong> {form.date || ""}</div>
      <div className="form-field"><strong>Time:</strong> {form.time || ""}</div>
      <div className="form-field"><strong>Topics Discussed:</strong> {form.topics || ""}</div>
      <div className="form-field"><strong>Outcomes:</strong> {form.outcomes || ""}</div>
      <div className="form-field">
        <strong>Follow-up:</strong> 
        {form.followup ? <a href="#">{form.followup}</a> : ""}
      </div>
      <div className="form-field">
        <strong>Sentiment:</strong> {form.sentiment ? `${sentimentEmoji[form.sentiment]} ${form.sentiment}` : ""}
      </div>
      <div className="form-field"><strong>Priority:</strong> {form.priority || ""}</div>
      <div className="form-field"><strong>Next Action:</strong> {form.next_action || ""}</div>

      {form.tags && form.tags.length > 0 && (
        <div className="form-field">
          <strong>Tags:</strong>
          <div className="tags">
            {form.tags.map((t, idx) => <span key={idx} className="tag">{t}</span>)}
          </div>
        </div>
      )}

      {form.email_summary && (
        <div className="form-field">
          <strong>Email Summary:</strong>
          <div className="email-summary">{form.email_summary}</div>
        </div>
      )}

      {form.compliance_issues && form.compliance_issues.length > 0 && (
        <div className="form-field compliance">
          <strong>Compliance Issues:</strong> {form.compliance_issues.join(", ")}
        </div>
      )}
    </div>
  );
}

export default InteractionForm;
